1	//! A faithful Rust port of the Hughes/Peyton-Jones pretty-printing library
2	//! `Text.PrettyPrint.HughesPJ` (Haskell `pretty` 1.1.3.6, BSD-licensed).
3	//!
4	//! OUT OF THE GPL-ERASURE SURFACE: this layout algebra was clean-roomed by the
5	//! graphdot cluster from the sanctioned BSD source
6	//! (`graphdot/sanctioned/pretty-1.1.3.6/src/Text/PrettyPrint/Annotated/
7	//! HughesPJ.hs`) and is vendored here unchanged (BSD terms permit), plus one
8	//! addition: [`render_with`], a renderer entry point taking an explicit
9	//! integer ribbon width (the theory echo uses width 110 / ribbon 73).
10	//!
11	//! This module implements the `Doc` document model and the combinators, the
12	//! best/fits layout selection, and the `PageMode` renderer: `<>`/`<+>`,
13	//! `$$`/`$+$`, `hcat`/`hsep`/`vcat`, `sep`/`cat`, `fsep`/`fcat`, `nest`/
14	//! `hang`, and the `best`/`nicest`/`fits` fitting logic with `lineLength` and
15	//! `ribbonsPerLine`.
16	//!
17	//! Nothing in this file is tamarin-specific: it is the general layout algebra.
18	//! WHICH combinators the theory echo applies, with what literal strings and
19	//! nesting, is derived from black-box probes and lives in the sibling modules
20	//! (`term`, `signature`, …); this module is the exact engine they feed.
21	//!
22	//! The annotation machinery of the original is elided (this port renders to a
23	//! plain `String`), so `TextBeside` carries the text and its column width
24	//! directly instead of an `AnnotDetails`.
25	//!
26	//! **Evaluation strategy.** The Haskell original relies on lazy evaluation: the
27	//! combinators (`sep`/`fill`/`beside`/`aboveNest`) describe exponentially large
28	//! sets of layouts as union trees, but `best` only ever forces the branches it
29	//! inspects, and `fits` only forces the *first line* of a candidate. A naive
30	//! strict port materializes those whole trees (exponential in the number of
31	//! fill elements). This port mirrors the laziness explicitly: recursive
32	//! combinator continuations are built as [`Doc::Lazy`] thunks (forced on
33	//! demand, memoized), and the `nicest` union choice uses [`fits_ahead`], which
34	//! decides `fits (min w r - sl) (best' ...)` by walking the *unresolved*
35	//! branch's first line only. Both are pure evaluation-order mirrors of the
36	//! sanctioned semantics: the resolved layout is byte-identical.
37	
38	use std::cell::RefCell;
39	use std::rc::Rc;
40	
41	/// The abstract document type. A `Doc` denotes a *set* of layouts; a `Doc` with
42	/// no `Union`/`NoDoc` denotes a single layout. Mirrors the Haskell `Doc a`
43	/// constructors (annotations elided).
44	#[derive(Clone, Debug)]
45	pub enum Doc {
46	    /// An empty span (`empty`): no height, no width.
47	    Empty,
48	    /// `text "" $$ x` — a newline above `x`. Its argument is never `Empty`.
49	    NilAbove(Rc<Doc>),
50	    /// `text s <> x` — literal text (with its column width) beside `x`. The
51	    /// argument is never a `Nest`.
52	    TextBeside(Rc<str>, usize, Rc<Doc>),
53	    /// `nest k x` — indent `x` by `k` columns (`k` may be negative).
54	    Nest(isize, Rc<Doc>),
55	    /// `ul \`union\` ur` — a choice between two layouts that flatten equal.
56	    Union(Rc<Doc>, Rc<Doc>),
57	    /// The empty *set* of documents.
58	    NoDoc,
59	    /// `Beside l sep r` — `sep` = true means a space is inserted between.
60	    Beside(Rc<Doc>, bool, Rc<Doc>),
61	    /// `Above u never_overlap l` — `never_overlap` = true forbids overlap.
62	    Above(Rc<Doc>, bool, Rc<Doc>),
63	    /// A suspended sub-document (the strict mirror of a Haskell thunk):
64	    /// computed on first [`force`], then memoized. Only ever wraps an already
65	    /// *reduced* document (an RDoc — no `Beside`/`Above`).
66	    Lazy(Rc<LazyDoc>),
67	}
68	
69	/// The shared state of a [`Doc::Lazy`] thunk.
70	pub struct LazyDoc(RefCell<LazyState>);
71	
72	enum LazyState {
73	    Pending(Option<Box<dyn FnOnce() -> Doc>>),
74	    Forced(Doc),
75	}
76	
77	impl std::fmt::Debug for LazyDoc {
78	    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
79	        match &*self.0.borrow() {
80	            LazyState::Pending(_) => write!(f, "Lazy(<pending>)"),
81	            LazyState::Forced(d) => write!(f, "Lazy({:?})", d),
82	        }
83	    }
84	}
85	
86	use Doc::*;
87	
88	fn rc(d: Doc) -> Rc<Doc> {
89	    Rc::new(d)
90	}
91	
92	/// Suspend a document computation (a thunk). The closure runs at most once.
93	fn lazy<F: FnOnce() -> Doc + 'static>(f: F) -> Doc {
94	    Lazy(Rc::new(LazyDoc(RefCell::new(LazyState::Pending(Some(
95	        Box::new(f),
96	    ))))))
97	}
98	
99	/// Force a document to its outermost non-`Lazy` constructor (shallow clone —
100	/// children stay shared via `Rc`). Thunks are computed once and memoized;
101	/// chains of thunks collapse to the final value.
102	fn force(d: &Doc) -> Doc {
103	    match d {
104	        Lazy(l) => {
105	            if let LazyState::Forced(v) = &*l.0.borrow() {
106	                return v.clone();
107	            }
108	            let f = match &mut *l.0.borrow_mut() {
109	                LazyState::Pending(f) => f.take().expect("re-entrant force"),
110	                LazyState::Forced(v) => return v.clone(),
111	            };
112	            let v = force(&f());
113	            *l.0.borrow_mut() = LazyState::Forced(v.clone());
114	            v
115	        }
116	        _ => d.clone(),
117	    }
118	}
119	
120	// ---------------------------------------------------------------------------
121	// Constructors (§ "Values and Predicates")
122	
123	/// A one-character document.
124	pub fn char(c: char) -> Doc {
125	    let mut buf = [0u8; 4];
126	    let s: &str = c.encode_utf8(&mut buf);
127	    TextBeside(Rc::from(s), 1, rc(Empty))
128	}
129	
130	/// A one-line literal string document; its width is its Unicode-scalar count.
131	pub fn text(s: &str) -> Doc {
132	    let len = s.chars().count();
133	    TextBeside(Rc::from(s), len, rc(Empty))
134	}
135	
136	/// Text with an explicit column width (`sizedText l s`); use width 0 for
137	/// non-printing text.
138	pub fn sized_text(len: usize, s: &str) -> Doc {
139	    TextBeside(Rc::from(s), len, rc(Empty))
140	}
141	
142	/// The empty document (identity for `<>`, `$$`, and list combinators).
143	pub fn empty() -> Doc {
144	    Empty
145	}
146	
147	/// Is this the empty document?
148	pub fn is_empty(d: &Doc) -> bool {
149	    matches!(force(d), Empty)
150	}
151	
152	
153	// ---------------------------------------------------------------------------
154	// Structural smart-constructors
155	
156	fn nil_above_(d: Rc<Doc>) -> Doc {
157	    NilAbove(d)
158	}
159	
160	fn text_beside_(s: Rc<str>, l: usize, d: Rc<Doc>) -> Doc {
161	    TextBeside(s, l, d)
162	}
163	
164	fn nest_(k: isize, d: Rc<Doc>) -> Doc {
165	    Nest(k, d)
166	}
167	
168	fn union_(a: Rc<Doc>, b: Rc<Doc>) -> Doc {
169	    Union(a, b)
170	}
171	
172	/// `reduceDoc`: push `Beside`/`Above` down into reduced form (RDoc).
173	pub fn reduce_doc(d: &Doc) -> Doc {
174	    match d {
175	        Beside(p, g, q) => beside(p, *g, &reduce_doc(q)),
176	        Above(p, g, q) => above(p, *g, &reduce_doc(q)),
177	        other => other.clone(),
178	    }
179	}
180	
181	// ---------------------------------------------------------------------------
182	// nest / mkNest / mkUnion
183	
184	/// `nest k p` — indent by `k` (may be negative).
185	pub fn nest(k: isize, p: &Doc) -> Doc {
186	    mk_nest(k, &reduce_doc(p))
187	}
188	
189	fn mk_nest(k: isize, d: &Doc) -> Doc {
190	    let df = force(d);
191	    match &df {
192	        Nest(k1, p) => mk_nest(k + k1, p),
193	        NoDoc => NoDoc,
194	        Empty => Empty,
195	        _ if k == 0 => df,
196	        _ => nest_(k, rc(df)),
197	    }
198	}
199	
200	fn mk_union(p: Doc, q: Doc) -> Doc {
201	    match force(&p) {
202	        Empty => Empty,
203	        pf => union_(rc(pf), rc(q)),
204	    }
205	}
206	
207	// ---------------------------------------------------------------------------
208	// Horizontal composition <> and <+>
209	
210	/// `p <> q` — beside.
211	pub fn beside_op(p: Doc, q: Doc) -> Doc {
212	    beside_(p, false, q)
213	}
214	
215	/// `p <+> q` — beside, separated by a space unless an argument is empty.
216	pub fn beside_space(p: Doc, q: Doc) -> Doc {
217	    beside_(p, true, q)
218	}
219	
220	fn beside_(p: Doc, g: bool, q: Doc) -> Doc {
221	    match (&p, &q) {
222	        (_, Empty) => p,
223	        (Empty, _) => q,
224	        _ => Beside(rc(p), g, rc(q)),
225	    }
226	}
227	
228	/// `beside p g q` (spec: `p <g> q`) over reduced docs. Union branches and the
229	/// text-tail continuation are suspended ([`lazy`]), mirroring the sanctioned
230	/// source's (non-`$!`) laziness.
231	fn beside(p: &Doc, g: bool, q: &Doc) -> Doc {
232	    let pf = force(p);
233	    match &pf {
234	        NoDoc => NoDoc,
235	        Union(p1, p2) => {
236	            let (p1, p2, qa, qb) = (p1.clone(), p2.clone(), q.clone(), q.clone());
237	            union_(
238	                rc(lazy(move || beside(&p1, g, &qa))),
239	                rc(lazy(move || beside(&p2, g, &qb))),
240	            )
241	        }
242	        Empty => q.clone(),
243	        Nest(k, p1) => nest_(*k, rc(beside(p1, g, q))),
244	        Beside(p1, g1, q1) => {
245	            if *g1 == g {
246	                beside(p1, *g1, &beside(q1, g, q))
247	            } else {
248	                beside(&reduce_doc(&pf), g, q)
249	            }
250	        }
251	        Above(..) => beside(&reduce_doc(&pf), g, q),
252	        NilAbove(p1) => nil_above_(rc(beside(p1, g, q))),
253	        TextBeside(s, l, p1) => {
254	            let (p1, q1) = (p1.clone(), q.clone());
255	            let rest = lazy(move || match force(&p1) {
256	                Empty => nil_beside(g, &q1),
257	                _ => beside(&p1, g, &q1),
258	            });
259	            text_beside_(s.clone(), *l, rc(rest))
260	        }
261	        Lazy(_) => unreachable!("beside: forced doc"),
262	    }
263	}
264	
265	/// `nilBeside g p` (spec: `text "" <g> p`).
266	fn nil_beside(g: bool, p: &Doc) -> Doc {
267	    let pf = force(p);
268	    match &pf {
269	        Empty => Empty,
270	        Nest(_, p1) => nil_beside(g, p1),
271	        _ => {
272	            if g {
273	                TextBeside(Rc::from(" "), 1, rc(pf))
274	            } else {
275	                pf
276	            }
277	        }
278	    }
279	}
280	
281	// ---------------------------------------------------------------------------
282	// Vertical composition $$ and $+$
283	
284	/// `p $$ q` — above, with overlap allowed.
285	pub fn above_op(p: Doc, q: Doc) -> Doc {
286	    above_(p, false, q)
287	}
288	
289	/// `p $+$ q` — above, no overlap.
290	pub fn above_plus(p: Doc, q: Doc) -> Doc {
291	    above_(p, true, q)
292	}
293	
294	fn above_(p: Doc, g: bool, q: Doc) -> Doc {
295	    match (&p, &q) {
296	        (_, Empty) => p,
297	        (Empty, _) => q,
298	        _ => Above(rc(p), g, rc(q)),
299	    }
300	}
301	
302	fn above(p: &Doc, g: bool, q: &Doc) -> Doc {
303	    let pf = force(p);
304	    match &pf {
305	        Above(p1, g1, q1) => above(p1, *g1, &above(q1, g, q)),
306	        Beside(..) => above_nest(&reduce_doc(&pf), g, 0, &reduce_doc(q)),
307	        _ => above_nest(&pf, g, 0, &reduce_doc(q)),
308	    }
309	}
310	
311	/// `aboveNest p g k q` (spec: `p $g$ (nest k q)`). Union branches and the
312	/// recursive continuations are suspended, mirroring the sanctioned laziness.
313	fn above_nest(p: &Doc, g: bool, k: isize, q: &Doc) -> Doc {
314	    let pf = force(p);
315	    match &pf {
316	        NoDoc => NoDoc,
317	        Union(p1, p2) => {
318	            let (p1, p2, qa, qb) = (p1.clone(), p2.clone(), q.clone(), q.clone());
319	            union_(
320	                rc(lazy(move || above_nest(&p1, g, k, &qa))),
321	                rc(lazy(move || above_nest(&p2, g, k, &qb))),
322	            )
323	        }
324	        Empty => mk_nest(k, q),
325	        Nest(k1, p1) => {
326	            let (k1, p1, q1) = (*k1, p1.clone(), q.clone());
327	            nest_(k1, rc(lazy(move || above_nest(&p1, g, k - k1, &q1))))
328	        }
329	        NilAbove(p1) => {
330	            let (p1, q1) = (p1.clone(), q.clone());
331	            nil_above_(rc(lazy(move || above_nest(&p1, g, k, &q1))))
332	        }
333	        TextBeside(s, l, p1) => {
334	            let k1 = k - (*l as isize);
335	            let (p1, q1) = (p1.clone(), q.clone());
336	            let rest = lazy(move || match force(&p1) {
337	                Empty => nil_above_nest(g, k1, &q1),
338	                _ => above_nest(&p1, g, k1, &q1),
339	            });
340	            text_beside_(s.clone(), *l, rc(rest))
341	        }
342	        Above(..) => panic!("aboveNest Above"),
343	        Beside(..) => panic!("aboveNest Beside"),
344	        Lazy(_) => unreachable!("aboveNest: forced doc"),
345	    }
346	}
347	
348	/// `nilAboveNest g k q` (spec: `text s <> (text "" $g$ nest k q)`).
349	fn nil_above_nest(g: bool, k: isize, q: &Doc) -> Doc {
350	    let qf = force(q);
351	    match &qf {
352	        Empty => Empty,
353	        Nest(k1, q1) => nil_above_nest(g, k + k1, q1),
354	        _ => {
355	            if !g && k > 0 {
356	                let ind = indent(k);
357	                let len = ind.chars().count();
358	                text_beside_(Rc::from(ind.as_str()), len, rc(qf))
359	            } else {
360	                nil_above_(rc(mk_nest(k, &qf)))
361	            }
362	        }
363	    }
364	}
365	
366	// ---------------------------------------------------------------------------
367	// List versions: hcat / hsep / vcat  (via reduceHoriz/reduceVert)
368	
369	#[derive(Clone, Copy)]
370	enum IsEmpty {
371	    // `Empty` mirrors the Haskell `reduceHoriz`/`reduceVert` return type; this
372	    // strict port only ever yields `NotEmpty`, but the variant is kept to match
373	    // the sanctioned source's shape.
374	    #[allow(dead_code)]
375	    Empty,
376	    NotEmpty,
377	}
378	
379	fn reduce_horiz(d: &Doc) -> (IsEmpty, Doc) {
380	    match d {
381	        Beside(p, g, q) => {
382	            let (_, pr) = reduce_horiz(p);
383	            eliminate_empty(true, pr, *g, reduce_horiz(q))
384	        }
385	        _ => (IsEmpty::NotEmpty, d.clone()),
386	    }
387	}
388	
389	fn reduce_vert(d: &Doc) -> (IsEmpty, Doc) {
390	    match d {
391	        Above(p, g, q) => {
392	            let (_, pr) = reduce_vert(p);
393	            eliminate_empty(false, pr, *g, reduce_vert(q))
394	        }
395	        _ => (IsEmpty::NotEmpty, d.clone()),
396	    }
397	}
398	
399	/// `beside_cons` = true builds `Beside`, false builds `Above`.
400	fn eliminate_empty(beside_cons: bool, p: Doc, g: bool, q: (IsEmpty, Doc)) -> (IsEmpty, Doc) {
401	    match p {
402	        Empty => q,
403	        _ => {
404	            let out = match q {
405	                (IsEmpty::NotEmpty, q1) => {
406	                    if beside_cons {
407	                        Beside(rc(p), g, rc(q1))
408	                    } else {
409	                        Above(rc(p), g, rc(q1))
410	                    }
411	                }
412	                (IsEmpty::Empty, _) => p,
413	            };
414	            (IsEmpty::NotEmpty, out)
415	        }
416	    }
417	}
418	
419	/// `hcat` — list version of `<>`.
420	pub fn hcat(ds: Vec<Doc>) -> Doc {
421	    let folded = ds
422	        .into_iter()
423	        .rev()
424	        .fold(Empty, |q, p| Beside(rc(p), false, rc(q)));
425	    reduce_horiz(&folded).1
426	}
427	
428	/// `hsep` — list version of `<+>`.
429	pub fn hsep(ds: Vec<Doc>) -> Doc {
430	    let folded = ds
431	        .into_iter()
432	        .rev()
433	        .fold(Empty, |q, p| Beside(rc(p), true, rc(q)));
434	    reduce_horiz(&folded).1
435	}
436	
437	/// `vcat` — list version of `$$`.
438	pub fn vcat(ds: Vec<Doc>) -> Doc {
439	    let folded = ds
440	        .into_iter()
441	        .rev()
442	        .fold(Empty, |q, p| Above(rc(p), false, rc(q)));
443	    reduce_vert(&folded).1
444	}
445	
446	/// `hang d1 n d2 = sep [d1, nest n d2]`.
447	pub fn hang(d1: Doc, n: isize, d2: Doc) -> Doc {
448	    sep(vec![d1, nest(n, &d2)])
449	}
450	
451	/// `punctuate p [d1,…,dn] = [d1<>p, …, d(n-1)<>p, dn]`.
452	pub fn punctuate(p: &Doc, ds: Vec<Doc>) -> Vec<Doc> {
453	    let n = ds.len();
454	    ds.into_iter()
455	        .enumerate()
456	        .map(|(i, d)| {
457	            if i + 1 < n {
458	                beside_op(d, p.clone())
459	            } else {
460	                d
461	            }
462	        })
463	        .collect()
464	}
465	
466	// ---------------------------------------------------------------------------
467	// sep / cat
468	
469	/// `sep` — either `hsep` (one line) or `vcat`.
470	pub fn sep(ds: Vec<Doc>) -> Doc {
471	    sep_x(true, ds)
472	}
473	
474	/// `cat` — either `hcat` (one line) or `vcat`.
475	pub fn cat(ds: Vec<Doc>) -> Doc {
476	    sep_x(false, ds)
477	}
478	
479	fn sep_x(x: bool, ds: Vec<Doc>) -> Doc {
480	    if ds.is_empty() {
481	        return Empty;
482	    }
483	    let mut it = ds.into_iter();
484	    let p = it.next().unwrap();
485	    let ys: Vec<Doc> = it.collect();
486	    sep1(x, &reduce_doc(&p), 0, &ys)
487	}
488	
489	fn sep1(g: bool, p: &Doc, k: isize, ys: &[Doc]) -> Doc {
490	    let pf = force(p);
491	    match &pf {
492	        NoDoc => NoDoc,
493	        Union(p1, q) => {
494	            let (p1, q) = (p1.clone(), q.clone());
495	            let (ya, yb) = (ys.to_vec(), ys.to_vec());
496	            union_(
497	                rc(lazy(move || sep1(g, &p1, k, &ya))),
498	                rc(lazy(move || {
499	                    above_nest(&q, false, k, &reduce_doc(&vcat(yb)))
500	                })),
501	            )
502	        }
503	        Empty => mk_nest(k, &sep_x(g, ys.to_vec())),
504	        Nest(n, p1) => {
505	            let (n, p1, ys) = (*n, p1.clone(), ys.to_vec());
506	            nest_(n, rc(lazy(move || sep1(g, &p1, k - n, &ys))))
507	        }
508	        NilAbove(p1) => {
509	            let (p1, ys) = (p1.clone(), ys.to_vec());
510	            nil_above_(rc(lazy(move || {
511	                above_nest(&p1, false, k, &reduce_doc(&vcat(ys)))
512	            })))
513	        }
514	        TextBeside(s, l, p1) => {
515	            let li = *l as isize;
516	            let (p1, ys) = (p1.clone(), ys.to_vec());
517	            text_beside_(
518	                s.clone(),
519	                *l,
520	                rc(lazy(move || sep_nb(g, &p1, k - li, &ys))),
521	            )
522	        }
523	        Above(..) => panic!("sep1 Above"),
524	        Beside(..) => panic!("sep1 Beside"),
525	        Lazy(_) => unreachable!("sep1: forced doc"),
526	    }
527	}
528	
529	fn sep_nb(g: bool, p: &Doc, k: isize, ys: &[Doc]) -> Doc {
530	    let pf = force(p);
531	    match &pf {
532	        Nest(_, p1) => sep_nb(g, p1, k, ys),
533	        Empty => {
534	            let rest = if g {
535	                hsep(ys.to_vec())
536	            } else {
537	                hcat(ys.to_vec())
538	            };
539	            let left = one_liner(&nil_beside(g, &reduce_doc(&rest)));
540	            let (k1, ys1) = (k, ys.to_vec());
541	            let right = lazy(move || nil_above_nest(false, k1, &reduce_doc(&vcat(ys1))));
542	            mk_union(left, right)
543	        }
544	        _ => sep1(g, &pf, k, ys),
545	    }
546	}
547	
548	// ---------------------------------------------------------------------------
549	// fill (fcat / fsep)
550	
551	/// `fcat` — paragraph-fill version of `cat` (no inter-element space).
552	pub fn fcat(ds: Vec<Doc>) -> Doc {
553	    fill(false, ds)
554	}
555	
556	/// `fsep` — paragraph-fill version of `sep` (space between elements).
557	pub fn fsep(ds: Vec<Doc>) -> Doc {
558	    fill(true, ds)
559	}
560	
561	fn fill(g: bool, ds: Vec<Doc>) -> Doc {
562	    if ds.is_empty() {
563	        return Empty;
564	    }
565	    let mut it = ds.into_iter();
566	    let p = it.next().unwrap();
567	    let ys: Vec<Doc> = it.collect();
568	    fill1(g, &reduce_doc(&p), 0, &ys)
569	}
570	
571	fn fill1(g: bool, p: &Doc, k: isize, ys: &[Doc]) -> Doc {
572	    let pf = force(p);
573	    match &pf {
574	        NoDoc => NoDoc,
575	        Union(p1, q) => {
576	            let (p1, q) = (p1.clone(), q.clone());
577	            let (ya, yb) = (ys.to_vec(), ys.to_vec());
578	            union_(
579	                rc(lazy(move || fill1(g, &p1, k, &ya))),
580	                rc(lazy(move || above_nest(&q, false, k, &fill(g, yb)))),
581	            )
582	        }
583	        Empty => mk_nest(k, &fill(g, ys.to_vec())),
584	        Nest(n, p1) => {
585	            let (n, p1, ys) = (*n, p1.clone(), ys.to_vec());
586	            nest_(n, rc(lazy(move || fill1(g, &p1, k - n, &ys))))
587	        }
588	        NilAbove(p1) => {
589	            let (p1, ys) = (p1.clone(), ys.to_vec());
590	            nil_above_(rc(lazy(move || {
591	                above_nest(&p1, false, k, &fill(g, ys))
592	            })))
593	        }
594	        TextBeside(s, l, p1) => {
595	            let li = *l as isize;
596	            let (p1, ys) = (p1.clone(), ys.to_vec());
597	            text_beside_(
598	                s.clone(),
599	                *l,
600	                rc(lazy(move || fill_nb(g, &p1, k - li, &ys))),
601	            )
602	        }
603	        Above(..) => panic!("fill1 Above"),
604	        Beside(..) => panic!("fill1 Beside"),
605	        Lazy(_) => unreachable!("fill1: forced doc"),
606	    }
607	}
608	
609	fn fill_nb(g: bool, p: &Doc, k: isize, ys: &[Doc]) -> Doc {
610	    let pf = force(p);
611	    match &pf {
612	        Nest(_, p1) => fill_nb(g, p1, k, ys),
613	        Empty => {
614	            if ys.is_empty() {
615	                Empty
616	            } else if matches!(force(&ys[0]), Empty) {
617	                fill_nb(g, &Empty, k, &ys[1..])
618	            } else {
619	                fill_nbe(g, k, &ys[0], &ys[1..])
620	            }
621	        }
622	        _ => fill1(g, &pf, k, ys),
623	    }
624	}
625	
626	fn fill_nbe(g: bool, k: isize, y: &Doc, ys: &[Doc]) -> Doc {
627	    let k1 = if g { k - 1 } else { k };
628	    let y_one = elide_nest(&one_liner(&reduce_doc(y)));
629	    let left = nil_beside(g, &fill1(g, &y_one, k1, ys));
630	    let (y2, ys2) = (y.clone(), ys.to_vec());
631	    let right = lazy(move || {
632	        let mut rest = vec![y2];
633	        rest.extend(ys2);
634	        nil_above_nest(false, k, &fill(g, rest))
635	    });
636	    mk_union(left, right)
637	}
638	
639	fn elide_nest(d: &Doc) -> Doc {
640	    let df = force(d);
641	    match &df {
642	        Nest(_, d1) => d1.as_ref().clone(),
643	        _ => df,
644	    }
645	}
646	
647	// ---------------------------------------------------------------------------
648	// Best layout: best / nicest / fits / oneLiner
649	
650	fn one_liner(d: &Doc) -> Doc {
651	    let df = force(d);
652	    match &df {
653	        NoDoc => NoDoc,
654	        Empty => Empty,
655	        NilAbove(_) => NoDoc,
656	        TextBeside(s, l, p) => {
657	            let p = p.clone();
658	            text_beside_(s.clone(), *l, rc(lazy(move || one_liner(&p))))
659	        }
660	        Nest(k, p) => {
661	            let (k, p) = (*k, p.clone());
662	            nest_(k, rc(lazy(move || one_liner(&p))))
663	        }
664	        Union(p, _) => one_liner(p),
665	        Above(..) => panic!("oneLiner Above"),
666	        Beside(..) => panic!("oneLiner Beside"),
667	        Lazy(_) => unreachable!("oneLiner: forced doc"),
668	    }
669	}
670	
671	/// `best w r doc` — resolve unions to a single layout for line width `w`,
672	/// ribbon width `r`. Mirrors the Haskell `best`/`nicest1` including its
673	/// laziness: the resolved document's tails are thunks, so `fits` (which only
674	/// inspects a candidate's *first line*) never forces a branch beyond that
675	/// line, and the right branch of a union is only resolved when the left's
676	/// first line does not fit.
677	fn best(w: isize, r: isize, d: &Doc) -> Doc {
678	    get(w, r, d)
679	}
680	
681	fn get(w: isize, r: isize, d: &Doc) -> Doc {
682	    let df = force(d);
683	    match &df {
684	        Empty => Empty,
685	        NoDoc => NoDoc,
686	        NilAbove(p) => {
687	            let p = p.clone();
688	            nil_above_(rc(lazy(move || get(w, r, &p))))
689	        }
690	        TextBeside(s, l, p) => {
691	            let (li, p) = (*l as isize, p.clone());
692	            text_beside_(s.clone(), *l, rc(lazy(move || get1(w, r, li, &p))))
693	        }
694	        Nest(k, p) => {
695	            let (k, p) = (*k, p.clone());
696	            nest_(k, rc(lazy(move || get(w - k, r, &p))))
697	        }
698	        Union(p, q) => nicest(w, r, p, q),
699	        Above(..) => panic!("best get Above"),
700	        Beside(..) => panic!("best get Beside"),
701	        Lazy(_) => unreachable!("get: forced doc"),
702	    }
703	}
704	
705	fn get1(w: isize, r: isize, sl: isize, d: &Doc) -> Doc {
706	    let df = force(d);
707	    match &df {
708	        Empty => Empty,
709	        NoDoc => NoDoc,
710	        NilAbove(p) => {
711	            let p = p.clone();
712	            nil_above_(rc(lazy(move || get(w - sl, r, &p))))
713	        }
714	        TextBeside(s, l, p) => {
715	            let (li, p) = (*l as isize, p.clone());
716	            text_beside_(
717	                s.clone(),
718	                *l,
719	                rc(lazy(move || get1(w, r, sl + li, &p))),
720	            )
721	        }
722	        Nest(_, p) => get1(w, r, sl, p),
723	        Union(p, q) => nicest1(w, r, sl, p, q),
724	        Above(..) => panic!("best get1 Above"),
725	        Beside(..) => panic!("best get1 Beside"),
726	        Lazy(_) => unreachable!("get1: forced doc"),
727	    }
728	}
729	
730	fn nicest(w: isize, r: isize, p: &Doc, q: &Doc) -> Doc {
731	    nicest1(w, r, 0, p, q)
732	}
733	
734	fn nicest1(w: isize, r: isize, sl: isize, p: &Doc, q: &Doc) -> Doc {
735	    // Resolve the left branch lazily; keep it iff its first line fits (`fits`
736	    // forces only that first line). Resolve the right branch only otherwise.
737	    let (pc, qc) = (p.clone(), q.clone());
738	    let lp = lazy(move || get1(w, r, sl, &pc));
739	    if fits(w.min(r) - sl, &lp) {
740	        lp
741	    } else {
742	        lazy(move || get1(w, r, sl, &qc))
743	    }
744	}
745	
746	/// True iff the *first line* of `d` fits in `n` columns. Forces only up to the
747	/// first line break of an already-`best`-resolved (thunked) document.
748	fn fits(n: isize, d: &Doc) -> bool {
749	    if n < 0 {
750	        return false;
751	    }
752	    match &force(d) {
753	        NoDoc => false,
754	        Empty => true,
755	        NilAbove(_) => true,
756	        TextBeside(_, l, p) => fits(n - *l as isize, p),
757	        Above(..) => panic!("fits Above"),
758	        Beside(..) => panic!("fits Beside"),
759	        Union(..) => panic!("fits Union"),
760	        Nest(..) => panic!("fits Nest"),
761	        Lazy(_) => unreachable!("fits: forced doc"),
762	    }
763	}
764	
765	// ---------------------------------------------------------------------------
766	// Rendering (PageMode only)
767	
768	fn indent(n: isize) -> String {
769	    if n <= 0 {
770	        String::new()
771	    } else {
772	        " ".repeat(n as usize)
773	    }
774	}
775	
776	/// Banker's-rounding of `line_len / ribbons` to match Haskell `round`.
777	fn round_ribbon(line_len: isize, ribbons: f64) -> isize {
778	    let v = line_len as f64 / ribbons;
779	    let floor = v.floor();
780	    let diff = v - floor;
781	    let rounded = if (diff - 0.5).abs() < 1e-9 {
782	        // round half to even
783	        let f = floor as i64;
784	        if f % 2 == 0 {
785	            f
786	        } else {
787	            f + 1
788	        }
789	    } else {
790	        v.round() as i64
791	    };
792	    rounded as isize
793	}
794	
795	/// Render a document in `PageMode` at line length `line_len` and
796	/// `ribbons_per_line`, producing the plain string (newline-separated lines,
797	/// each continuation prefixed by its indentation spaces).
798	pub fn render_page(line_len: isize, ribbons_per_line: f64, doc: &Doc) -> String {
799	    let ribbon_len = round_ribbon(line_len, ribbons_per_line);
800	    let reduced = reduce_doc(doc);
801	    let best_doc = best(line_len, ribbon_len, &reduced);
802	    display_page(line_len, ribbon_len, &best_doc)
803	}
804	
805	/// Render in `PageMode` with an EXPLICIT ribbon width (columns), bypassing the
806	/// `ribbons_per_line` division. The theory echo renders at `render_with(110,
807	/// 73, doc)`.
808	pub fn render_with(line_len: isize, ribbon_len: isize, doc: &Doc) -> String {
809	    let reduced = reduce_doc(doc);
810	    let best_doc = best(line_len, ribbon_len, &reduced);
811	    display_page(line_len, ribbon_len, &best_doc)
812	}
813	
814	fn display_page(page_width: isize, ribbon_width: isize, doc: &Doc) -> String {
815	    let _gap = page_width - ribbon_width;
816	    let mut out = String::new();
817	    lay(&mut out, 0, doc);
818	    out
819	}
820	
821	fn lay(out: &mut String, k: isize, d: &Doc) {
822	    match &force(d) {
823	        Nest(k1, p) => lay(out, k + k1, p),
824	        Empty => {}
825	        NilAbove(p) => {
826	            out.push('\n');
827	            lay(out, k, p);
828	        }
829	        TextBeside(s, l, p) => lay1(out, k, s, *l, p),
830	        Above(..) => panic!("display lay Above"),
831	        Beside(..) => panic!("display lay Beside"),
832	        NoDoc => panic!("display lay NoDoc"),
833	        Union(..) => panic!("display lay Union"),
834	        Lazy(_) => unreachable!("lay: forced doc"),
835	    }
836	}
837	
838	fn lay1(out: &mut String, k: isize, s: &str, l: usize, p: &Doc) {
839	    out.push_str(&indent(k));
840	    out.push_str(s);
841	    lay2(out, k + l as isize, p);
842	}
843	
844	fn lay2(out: &mut String, k: isize, d: &Doc) {
845	    match &force(d) {
846	        NilAbove(p) => {
847	            out.push('\n');
848	            lay(out, k, p);
849	        }
850	        TextBeside(s, l, p) => {
851	            out.push_str(s);
852	            lay2(out, k + *l as isize, p);
853	        }
854	        Nest(_, p) => lay2(out, k, p),
855	        Empty => {}
856	        Above(..) => panic!("display lay2 Above"),
857	        Beside(..) => panic!("display lay2 Beside"),
858	        NoDoc => panic!("display lay2 NoDoc"),
859	        Union(..) => panic!("display lay2 Union"),
860	        Lazy(_) => unreachable!("lay2: forced doc"),
861	    }
862	}
