1	//! R1 — TERM rendering (the deep core; every other sub-target reuses this).
2	//!
3	//! Every glyph, spacing and parenthesization rule here is oracle-pinned; see
4	//! workspace/BEHAVIOR.md "Term rendering" for the probe provenance of each
5	//! case. Summary of the observed surface:
6	//!
7	//!   * sort sigils `~ $ # %` + `.idx` suffix when the index is > 0;
8	//!   * public constants `'name'`, fresh constants `~'name'`, naturals `%n`,
9	//!     DH constants `one` / `DH_neutral`;
10	//!   * application `f(a, b)` — comma attached to the preceding argument, fill
11	//!     space between arguments, wrap aligned after `(`; arity 0 renders bare;
12	//!   * tuples `<a, b, c>` — `", "` attached to each element (a wrapped line
13	//!     keeps the trailing space), right-nested pairs flattened;
14	//!   * `^` chains render flat for BOTH association orders, no parens added;
15	//!   * AC operators `*`, `⊕`, `++`, `%+` — self-parenthesized `(a*b*c)`,
16	//!     flattened across both sides, no spaces, break between elements with
17	//!     the operator attached to the preceding element;
18	//!   * `diff(l, r)` in application form.
19	
20	use crate::ast::{BinOp, SortHint, SuffixSort, Term, VarSpec};
21	use crate::doc::{
22	    beside_op, char, fcat, fsep, nest, punctuate, render_with, text, Doc,
23	};
24	
25	/// Theory-echo layout parameters (SPEC; every wrap observation in
26	/// BEHAVIOR.md reproduces at these settings).
27	pub(crate) const WIDTH: isize = 110;
28	pub(crate) const RIBBON: isize = 73;
29	
30	/// Render one term at the echo's layout parameters, starting at column 0.
31	pub fn render(t: &Term) -> String {
32	    render_with(WIDTH, RIBBON, &doc(t))
33	}
34	
35	/// The term's `Doc` (embedded by the signature/rule/formula renderers).
36	pub(crate) fn doc(t: &Term) -> Doc {
37	    match t {
38	        Term::Var(v) => text(&var_str(v)),
39	        Term::PubLit(s) => text(&format!("'{s}'")),
40	        Term::FreshLit(s) => text(&format!("~'{s}'")),
41	        Term::NatLit(s) => text(&format!("%{s}")),
42	        Term::Number(n) => text(&format!("%{n}")),
43	        Term::NumberOne => text("one"),
44	        Term::NatOne => text("%1"),
45	        Term::DhNeutral => text("DH_neutral"),
46	        Term::App(f, args) => {
47	            if args.is_empty() {
48	                text(f)
49	            } else {
50	                app_doc(f, args)
51	            }
52	        }
53	        Term::AlgApp(name, a, b) => {
54	            if name == "exp" {
55	                exp_doc(t)
56	            } else {
57	                app_doc(name, &[(**a).clone(), (**b).clone()])
58	            }
59	        }
60	        Term::Pair(elems) => pair_doc(elems),
61	        Term::Diff(l, r) => app_doc("diff", &[(**l).clone(), (**r).clone()]),
62	        Term::BinOp(BinOp::Exp, _, _) => exp_doc(t),
63	        Term::BinOp(op, _, _) => ac_doc(*op, t),
64	        // UNOBSERVABLE placeholder (BEHAVIOR.md): not oracle-pinned.
65	        Term::PatMatch(inner) => beside_op(text("="), doc(inner)),
66	    }
67	}
68	
69	/// Sigil + name + `.idx` suffix (suffix only when idx > 0).
70	fn var_str(v: &VarSpec) -> String {
71	    let sigil = match v.sort {
72	        SortHint::Msg | SortHint::Untagged | SortHint::Suffix(SuffixSort::Msg) => "",
73	        SortHint::Pub | SortHint::Suffix(SuffixSort::Pub) => "$",
74	        SortHint::Fresh | SortHint::Suffix(SuffixSort::Fresh) => "~",
75	        SortHint::Node | SortHint::Suffix(SuffixSort::Node) => "#",
76	        SortHint::Nat | SortHint::Suffix(SuffixSort::Nat) => "%",
77	    };
78	    if v.idx > 0 {
79	        format!("{sigil}{}.{}", v.name, v.idx)
80	    } else {
81	        format!("{sigil}{}", v.name)
82	    }
83	}
84	
85	/// `f(a1, a2, …)`: commas attach to the preceding argument, fill space
86	/// between arguments (fsep), wrap aligns after the `(`, `)` attaches to the
87	/// last argument (probe:t_wide W2, probe:e_long).
88	fn app_doc(f: &str, args: &[Term]) -> Doc {
89	    let arg_docs = punctuate(&char(','), args.iter().map(doc).collect());
90	    beside_op(
91	        beside_op(text(&format!("{f}(")), fsep(arg_docs)),
92	        char(')'),
93	    )
94	}
95	
96	/// `<a, b, c>`: one fill whose items are `<`, each element (with attached
97	/// `", "` — a wrapped line keeps the trailing space, probe:t_wide W1,
98	/// probe:p_pw1) under `nest 1`, and `>`. The fill semantics produce every
99	/// observed wide-tuple shape (probe:p_pw1 wfa–wfd, target:mesh k2):
100	///   * fits → `<a, b>` on one line;
101	///   * elements fill-wrap at (column of `<`) + 1 (the nest 1);
102	///   * a first element whose one-liner does not fit beside `<` leaves `<`
103	///     ALONE on its line;
104	///   * `>` sits beside the last element when that element ends a fill line,
105	///     but drops to its own line at the column of `<` (no nest) when the
106	///     last element is multi-line.
107	/// A Pair in LAST position flattens into the enclosing tuple; other positions
108	/// keep their own delimiters (probe:t_pair).
109	fn pair_doc(elems: &[Term]) -> Doc {
110	    let mut flat: Vec<&Term> = Vec::new();
111	    collect_pair(elems, &mut flat);
112	    let mut items = vec![char('<')];
113	    for d in punctuate(&text(", "), flat.into_iter().map(doc).collect()) {
114	        items.push(nest(1, &d));
115	    }
116	    items.push(char('>'));
117	    fcat(items)
118	}
119	
120	fn collect_pair<'a>(elems: &'a [Term], out: &mut Vec<&'a Term>) {
121	    for (i, e) in elems.iter().enumerate() {
122	        match e {
123	            Term::Pair(inner) if i + 1 == elems.len() => collect_pair(inner, out),
124	            _ => out.push(e),
125	        }
126	    }
127	}
128	
129	/// `a^b^c`: chains flatten for BOTH association orders (probe:t_exp2), the
130	/// `^` attaches to the preceding operand, no spaces, no parens added.
131	fn exp_doc(t: &Term) -> Doc {
132	    let mut leaves: Vec<&Term> = Vec::new();
133	    collect_exp(t, &mut leaves);
134	    let docs = punctuate(&char('^'), leaves.into_iter().map(doc).collect());
135	    fcat(docs)
136	}
137	
138	fn collect_exp<'a>(t: &'a Term, out: &mut Vec<&'a Term>) {
139	    match t {
140	        Term::BinOp(BinOp::Exp, a, b) => {
141	            collect_exp(a, out);
142	            collect_exp(b, out);
143	        }
144	        Term::AlgApp(name, a, b) if name == "exp" => {
145	            collect_exp(a, out);
146	            collect_exp(b, out);
147	        }
148	        _ => out.push(t),
149	    }
150	}
151	
152	/// AC operator: `(a<op>b<op>c)` — self-parenthesized, flattened across both
153	/// sides, operator attached to the preceding element, no spaces, fcat break
154	/// between elements (probes:t_xor, t_uni, t_nat, t_mult2, t_uniwide).
155	fn ac_doc(op: BinOp, t: &Term) -> Doc {
156	    let glyph = match op {
157	        BinOp::Mult => "*",
158	        BinOp::Union => "++",
159	        BinOp::Xor => "\u{2295}",
160	        BinOp::NatPlus => "%+",
161	        BinOp::Exp => unreachable!("Exp renders via exp_doc"),
162	    };
163	    let mut leaves: Vec<&Term> = Vec::new();
164	    collect_ac(op, t, &mut leaves);
165	    let docs = punctuate(&text(glyph), leaves.into_iter().map(doc).collect());
166	    beside_op(beside_op(char('('), fcat(docs)), char(')'))
167	}
168	
169	fn collect_ac<'a>(op: BinOp, t: &'a Term, out: &mut Vec<&'a Term>) {
170	    match t {
171	        Term::BinOp(o, a, b) if *o == op => {
172	            collect_ac(op, a, out);
173	            collect_ac(op, b, out);
174	        }
175	        _ => out.push(t),
176	    }
177	}
