407	// ── whole-rule-block parity over the round-2 curated captures ───────────────
408	
409	/// Slice a capture into its rule blocks: each spans the `rule …` header
410	/// through the trailing variants comment (including the interior blank line
411	/// and any loop-breaker line).
412	fn rule_blocks(capture: &str) -> Vec<String> {
413	    let lines: Vec<&str> = capture.lines().collect();
414	    let mut blocks = Vec::new();
415	    let mut i = 0;
416	    while i < lines.len() {
417	        if !lines[i].starts_with("rule ") {
418	            i += 1;
419	            continue;
420	        }
421	        let start = i;
422	        // Body: up to the first blank line.
423	        while i < lines.len() && !lines[i].is_empty() {
424	            i += 1;
425	        }
426	        // Optional loop-breaker annotation line(s).
427	        let mut j = i + 1;
428	        while j < lines.len() && lines[j].trim_start().starts_with("// loop breaker") {
429	            j += 1;
430	        }
431	        // The variants comment: one-liner or a /* … */ span.
432	        let end = if lines[j].trim() == "/* has exactly the trivial AC variant */" {
433	            j
434	        } else {
435	            assert_eq!(lines[j].trim(), "/*", "unexpected comment opener");
436	            let mut k = j + 1;
437	            while lines[k].trim() != "*/" {
438	                k += 1;
439	            }
440	            k
441	        };
442	        blocks.push(lines[start..=end].join("\n"));
443	        i = end + 1;
444	    }
445	    blocks
446	}
