853	#[test]
854	fn parity_rule_blocks_match_captures() {
855	    // The Doc engine recurses deeply on very large variant comments (Joux
856	    // has a 160-variant block), so run on a wide stack.
857	    std::thread::Builder::new()
858	        .stack_size(512 * 1024 * 1024)
859	        .spawn(parity_rule_blocks_impl)
860	        .unwrap()
861	        .join()
862	        .unwrap();
863	}
864	
865	fn parity_rule_blocks_impl() {
866	    // Sealed-workspace location of the curated round-2 captures; self-skips
867	    // once the crate moves at integration (the corpus gate takes over).
868	    let dir = std::path::Path::new("../../round2/targets");
869	    if !dir.is_dir() {
870	        return;
871	    }
872	    let mut checked = 0;
873	    for entry in std::fs::read_dir(dir).unwrap() {
874	        let path = entry.unwrap().path();
875	        if path.extension().and_then(|e| e.to_str()) != Some("txt") {
876	            continue;
877	        }
878	        let capture = std::fs::read_to_string(&path).unwrap();
879	        for (i, block) in rule_blocks(&capture).iter().enumerate() {
880	            let (r, v) = parse_block(block);
881	            let rendered = render_rule(&r, v.as_ref());
882	            assert_eq!(
883	                &rendered,
884	                block,
885	                "rule-block divergence: {} block #{i} ({})",
886	                path.display(),
887	                r.name
888	            );
889	            checked += 1;
890	        }
891	    }
892	    assert!(checked > 50, "expected many rule blocks, got {checked}");
893	}
