    /// Renders `⊤`.
    True,
    Atom(Atom),
    /// Renders `¬(…)` — the argument always parenthesized (probe:q_p2 s8).
    Not(Box<Formula>),
    /// Renders `(l) ∧ (r)`.
    And(Box<Formula>, Box<Formula>),
    /// Renders `(l) ∨ (r)`.
    Or(Box<Formula>, Box<Formula>),
    /// Renders `(l) ⇒ (r)`.
    Implies(Box<Formula>, Box<Formula>),
    /// Renders `(l) ⇔ (r)` (probe:q_r2).
